// 1. Obtener el texto CSV del nodo HTTP Request
const rawData = $input.all()[0].json.data || $input.all()[0].json.body || $input.all()[0].json;
const csvText = typeof rawData === 'string' ? rawData : JSON.stringify(rawData);

// Función simple para parsear el CSV en un array de objetos
function parseCSV(text) {
  const lines = text.split('\n').map(line => line.trim()).filter(line => line.length > 0);
  if (lines.length === 0) return [];

  const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
  const result = [];

  for (let i = 1; i < lines.length; i++) {
    const currentLine = lines[i].split(',').map(v => v.trim().replace(/^"|"$/g, ''));
    if (currentLine.length === headers.length) {
      const obj = {};
      for (let j = 0; j < headers.length; j++) {
        obj[headers[j]] = currentLine[j];
      }
      result.push(obj);
    }
  }
  return result;
}

const tutorias = parseCSV(csvText);

// 2. Definir límites de la semana actual (Viernes 17 de Julio de 2026)
const hoy = new Date("2026-07-17T12:00:00"); // Forzamos la fecha de hoy para la evaluación
const diaDeLaSemana = hoy.getDay(); // 0: Domingo, 1: Lunes...

// Calcular el lunes de esta semana (13 de Julio de 2026)
const diferenciaAlLunes = hoy.getDate() - diaDeLaSemana + (diaDeLaSemana === 0 ? -6 : 1);
const inicioSemana = new Date(hoy);
inicioSemana.setDate(diferenciaAlLunes);
inicioSemana.setHours(0, 0, 0, 0);

// Calcular el domingo de esta semana (19 de Julio de 2026)
const finSemana = new Date(inicioSemana);
finSemana.setDate(inicioSemana.getDate() + 6);
finSemana.setHours(23, 59, 59, 999);

// 3. Inicializar contadores
let matematicasCount = 0;
let programacionCount = 0;
let quimicaCount = 0;
let totalSemana = 0;

// 4. Procesar tutorías
for (const tutoria of tutorias) {
  const fechaStr = tutoria.fecha;
  const materiaRaw = tutoria.materia;

  if (!fechaStr || !materiaRaw) continue;

  const fechaTutoria = new Date(fechaStr + "T12:00:00"); // Evitar desfase de zona horaria
  const materia = materiaRaw.toLowerCase();

  // Validar si está dentro del rango
  if (fechaTutoria >= inicioSemana && fechaTutoria <= finSemana) {
    if (materia.includes('matem') || materia.includes('algebra') || materia.includes('calculo')) {
      matematicasCount++;
      totalSemana++;
    } else if (materia.includes('prog') || materia.includes('code') || materia.includes('desarrollo')) {
      programacionCount++;
      totalSemana++;
    } else if (materia.includes('quim') || materia.includes('química')) {
      quimicaCount++;
      totalSemana++;
    }
  }
}

// 5. Generar plantilla
const mensajeReporte = `📚 Resumen de Tutorías por Materia

----------------------------

🧮 Matemáticas: ${matematicasCount}

💻 Programación: ${programacionCount}

🧪 Química: ${quimicaCount}

📈 TOTAL SEMANA: ${totalSemana}`;

return [{ json: { mensaje_reporte: mensajeReporte } }];
